import{_ as s,c as n,o as e,a1 as l}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"고급: 스킬 생태계 관리 | opencode-agent-skills","description":"opencode-agent-skills의 고급 기능을 마스터하세요. Claude Code 호환성, Superpowers 통합, 네임스페이스 및 컨텍스트 압축 메커니즘을 포함하여 스킬 관리 능력을 향상시킵니다.","frontmatter":{"title":"고급: 스킬 생태계 관리 | opencode-agent-skills","sidebarTitle":"복잡한 스킬 생태계 관리하기","subtitle":"고급 기능","order":3,"description":"opencode-agent-skills의 고급 기능을 마스터하세요. Claude Code 호환성, Superpowers 통합, 네임스페이스 및 컨텍스트 압축 메커니즘을 포함하여 스킬 관리 능력을 향상시킵니다."},"headers":[],"relativePath":"ko/joshuadavidthomas/opencode-agent-skills/advanced/index.md","filePath":"ko/joshuadavidthomas/opencode-agent-skills/advanced/index.md"}'),i={name:"ko/joshuadavidthomas/opencode-agent-skills/advanced/index.md"};function p(o,a,t,r,d,c){return e(),n("div",null,[...a[0]||(a[0]=[l(`<h1 id="고급-기능" tabindex="-1">고급 기능 <a class="header-anchor" href="#고급-기능" aria-label="Permalink to &quot;고급 기능&quot;">​</a></h1><p>본 장에서는 OpenCode Agent Skills의 고급 기능을 심도 있게 다룹니다. Claude Code 호환성, Superpowers 워크플로우 통합, 네임스페이스 우선순위 시스템, 컨텍스트 압축 복구 메커니즘을 포함합니다. 이러한 내용을 마스터하면 복잡한 스킬 생태계를 더 효과적으로 관리하고, 긴 세션에서 스킬이 항상 사용 가능하도록 할 수 있습니다.</p><h2 id="전제-조건" tabindex="-1">전제 조건 <a class="header-anchor" href="#전제-조건" aria-label="Permalink to &quot;전제 조건&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">시작 전 확인</p><p>이 장을 학습하기 전에 다음을 완료했는지 확인하세요:</p><ul><li><a href="./../start/installation/">OpenCode Agent Skills 설치</a> - 플러그인이 올바르게 설치되고 실행 중인지 확인</li><li><a href="./../start/creating-your-first-skill/">첫 번째 스킬 만들기</a> - 스킬의 기본 구조 이해</li><li><a href="./../platforms/skill-discovery-mechanism/">스킬 발견 메커니즘 상세 설명</a> - 스킬이 어디에서 발견되는지 이해</li><li><a href="./../platforms/loading-skills-into-context/">세션 컨텍스트에 스킬 로드</a> - <code>use_skill</code> 도구 사용법 마스터</li></ul></div><h2 id="이-장의-내용" tabindex="-1">이 장의 내용 <a class="header-anchor" href="#이-장의-내용" aria-label="Permalink to &quot;이 장의 내용&quot;">​</a></h2><div class="grid-cards"><a href="./claude-code-compatibility/" class="card"><h3>Claude Code 스킬 호환성</h3><p>플러그인이 Claude Code의 스킬 및 플러그인 시스템과 호환되는 방법을 이해하고, 도구 매핑 메커니즘을 마스터하여 Claude 스킬 생태계를 재사용하세요.</p></a><a href="./superpowers-integration/" class="card"><h3>Superpowers 워크플로우 통합</h3><p>Superpowers 모드를 구성하고 사용하여 엄격한 소프트웨어 개발 워크플로우 지침을 얻고, 개발 효율성과 코드 품질을 향상시키세요.</p></a><a href="./namespaces-and-priority/" class="card"><h3>네임스페이스와 스킬 우선순위</h3><p>스킬의 네임스페이스 시스템과 발견 우선순위 규칙을 이해하고, 동일한 이름의 스킬 충돌을 해결하며, 스킬 소스를 정확하게 제어하세요.</p></a><a href="./context-compaction-resilience/" class="card"><h3>컨텍스트 압축 복구 메커니즘</h3><p>스킬이 긴 세션에서 사용 가능한 상태를 유지하는 방법을 이해하고, 압축 복구의 트리거 시점과 실행 프로세스를 마스터하세요.</p></a></div><h2 id="학습-경로" tabindex="-1">학습 경로 <a class="header-anchor" href="#학습-경로" aria-label="Permalink to &quot;학습 경로&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                           권장 학습 순서                                   │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│                                                                         │</span></span>
<span class="line"><span>│   1. Claude Code 호환  ──→  2. Superpowers 통합  ──→  3. 네임스페이스       │</span></span>
<span class="line"><span>│         │                        │                        │             │</span></span>
<span class="line"><span>│         ▼                        ▼                        ▼             │</span></span>
<span class="line"><span>│   Claude 스킬 재사용          워크플로우 지침 활성화          스킬 소스 정밀 제어     │</span></span>
<span class="line"><span>│                                                                         │</span></span>
<span class="line"><span>│                                  │                                      │</span></span>
<span class="line"><span>│                                  ▼                                      │</span></span>
<span class="line"><span>│                                                                         │</span></span>
<span class="line"><span>│                         4. 컨텍스트 압축 복구                                │</span></span>
<span class="line"><span>│                                  │                                      │</span></span>
<span class="line"><span>│                                  ▼                                      │</span></span>
<span class="line"><span>│                         긴 세션 스킬 지속성                                 │</span></span>
<span class="line"><span>│                                                                         │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────────────────┘</span></span></code></pre></div><p><strong>순서대로 학습하는 것을 권장합니다</strong>:</p><ol><li><strong>Claude Code 호환 먼저 학습</strong> - Claude Code 스킬이 있거나 Claude 플러그인 마켓의 스킬을 사용하려는 경우, 이것이 첫 번째 단계입니다</li><li><strong>다음으로 Superpowers 통합 학습</strong> - 엄격한 워크플로우 지침을 원하는 사용자, 활성화 및 구성 방법 이해</li><li><strong>그 다음 네임스페이스 학습</strong> - 스킬 수가 늘어나고 동일한 이름의 충돌이 발생할 때, 이 지식이 핵심적입니다</li><li><strong>마지막으로 압축 복구 학습</strong> - 긴 세션에서 스킬이 사용 가능한 상태를 유지하는 방법 이해, 원리 중심의 내용</li></ol><div class="tip custom-block"><p class="custom-block-title">필요에 따라 학습</p><ul><li><strong>Claude Code에서 마이그레이션</strong>: 제 1과(호환성)와 제 3과(네임스페이스)를 중점적으로 학습</li><li><strong>워크플로우 표준화</strong>: 제 2과(Superpowers)를 중점적으로 학습</li><li><strong>스킬 충돌 발생</strong>: 제 3과(네임스페이스)를 바로 참조</li><li><strong>긴 세션 스킬 손실</strong>: 제 4과(압축 복구)를 바로 참조</li></ul></div><h2 id="다음-단계" tabindex="-1">다음 단계 <a class="header-anchor" href="#다음-단계" aria-label="Permalink to &quot;다음 단계&quot;">​</a></h2><p>이 장을 완료한 후, 다음을 계속 학습할 수 있습니다:</p><ul><li><a href="./../faq/troubleshooting/">일반적인 문제 해결</a> - 문제 발생 시 문제 해결 가이드 참조</li><li><a href="./../faq/security-considerations/">보안 고려사항</a> - 플러그인의 보안 메커니즘과 모범 사례 이해</li><li><a href="./../appendix/api-reference/">API 도구 참조</a> - 사용 가능한 모든 도구의 자세한 매개변수 및 반환값 확인</li><li><a href="./../appendix/best-practices/">스킬 개발 모범 사례</a> - 고품질 스킬 작성을 위한 기술과 규범 마스터</li></ul>`,14)])])}const g=s(i,[["render",p]]);export{u as __pageData,g as default};
